// tests/first-test.spec.ts
import { test, expect } from '@playwright/test';

test('visit Playwright homepage', async ({ page }) => {
  // Navigate to the Playwright website
  await page.goto('https://playwright.dev');

  // Verify the page title
  await expect(page).toHaveTitle(/Playwright/);

  // Check if the main heading is visible
  const heading = page.locator('h1');
  await expect(heading).toBeVisible();

  // Verify the heading contains expected text
  await expect(heading).toContainText('Playwright');
});

// Key points:
// 1. Always use 'await' with Playwright methods
// 2. page.goto() navigates to a URL
// 3. expect() creates assertions
// 4. Assertions automatically wait for conditions to be met

