// tests/interactions.spec.ts
import { test, expect } from '@playwright/test';

test('basic interactions', async ({ page }) => {
  await page.goto('https://demo.playwright.dev/todomvc');

  // Type text into an input field
  const input = page.locator('.new-todo');
  await input.fill('Buy groceries');

  // Press Enter key
  await input.press('Enter');

  // Click a button or element
  await page.click('text=Active');

  // Double-click
  await page.dblclick('.todo-list li');

  // Right-click (context menu)
  await page.click('.todo-list li', { button: 'right' });

  // Hover over an element
  await page.hover('.todo-count');

  // Focus an element
  await page.focus('.new-todo');

  // Select option from dropdown
  await page.selectOption('select#sort', 'price');
});

// Pro tips:
// - fill() clears existing content first
// - type() types character by character (slower but more realistic)
// - All methods auto-wait for element to be ready

// tests/assertions.spec.ts
import { test, expect } from '@playwright/test';

test('using assertions', async ({ page }) => {
  await page.goto('https://playwright.dev');

  // Page assertions
  await expect(page).toHaveTitle(/Playwright/);
  await expect(page).toHaveURL('https://playwright.dev/');

  // Element visibility
  const getStarted = page.locator('text=Get Started');
  await expect(getStarted).toBeVisible();
  await expect(getStarted).toBeEnabled();

  // Text content
  await expect(getStarted).toHaveText('Get Started');
  await expect(getStarted).toContainText('Started');

  // Element attributes
  const link = page.locator('a.navbar__item');
  await expect(link).toHaveAttribute('href', '/docs/intro');

  // CSS properties
  await expect(getStarted).toHaveCSS('color', 'rgb(255, 255, 255)');

  // Element count
  const items = page.locator('.navbar__item');
  await expect(items).toHaveCount(5);

  // Negative assertions
  await expect(page.locator('.error')).not.toBeVisible();
  await expect(page).not.toHaveURL(/login/);
});

// Important:
// - Always use 'await' with expect()
// - Assertions auto-retry until timeout (5 seconds default)
// - This eliminates flakiness from timing issues

// tests/todo-app.spec.ts - A complete real-world test
import { test, expect } from '@playwright/test';

test.describe('Todo Application', () => {

  test('user can add and complete todos', async ({ page }) => {
    // Navigate to the app
    await page.goto('https://demo.playwright.dev/todomvc');

    // Add first todo
    const input = page.locator('.new-todo');
    await input.fill('Buy milk');
    await input.press('Enter');

    // Verify todo was added
    const firstTodo = page.locator('.todo-list li').first();
    await expect(firstTodo).toHaveText('Buy milk');

    // Add second todo
    await input.fill('Walk the dog');
    await input.press('Enter');

    // Verify count
    await expect(page.locator('.todo-list li')).toHaveCount(2);

    // Complete first todo
    await firstTodo.locator('.toggle').check();

    // Verify it's marked as completed
    await expect(firstTodo).toHaveClass(/completed/);

    // Verify counter updated
    await expect(page.locator('.todo-count')).toHaveText('1 item left');
  });

  test('user can filter todos', async ({ page }) => {
    await page.goto('https://demo.playwright.dev/todomvc');

    // Add and complete a todo
    await page.fill('.new-todo', 'Test task');
    await page.press('.new-todo', 'Enter');
    await page.check('.toggle');

    // Click Completed filter
    await page.click('text=Completed');

    // Verify URL changed
    await expect(page).toHaveURL(/completed/);

    // Verify completed todo is visible
    await expect(page.locator('.todo-list li')).toHaveCount(1);

    // Click Active filter
    await page.click('text=Active');

    // Verify no active todos
    await expect(page.locator('.todo-list li')).toHaveCount(0);
  });
});

// Best practices demonstrated:
// 1. Use test.describe() to group related tests
// 2. Give tests descriptive names
// 3. Add multiple assertions to verify behavior thoroughly
// 4. Test realistic user workflows

